+		const elapsedMs = activeAnswerStart === null ? 0 : Date.now() - activeAnswerStart;
+		activeAnswerStart = null;
+		ctx.ui.setWidget(WIDGET_KEY, renderSummary(ctx, elapsedMs), { placement: "aboveEditor" });
+	});
