     5	const CATPPUCCIN_MACCHIATO_PINK = "#f5bde6";
     6	const CATPPUCCIN_MACCHIATO_BLUE = "#8aadf4";
     7	const CATPPUCCIN_MACCHIATO_GREEN = "#a6da95";
     8	const CATPPUCCIN_MACCHIATO_RED = "#ed8796";
     9	const WIDGET_KEY = "answer-summary:final";
    10	const MAX_FILE_ROWS = 8;
    11	const MAX_TEXT_BYTES = 5 * 1024 * 1024;
    12	
    13	type FileSnapshot =
    14		| { kind: "text"; content: string | null }
    15		| { kind: "skipped"; reason: string };
    16	
    17	type FileStats = {
    18		path: string;
    19		name: string;
    20		status: "added" | "deleted" | "modified";
    21		added: number;
    22		removed: number;
    23	};
