    25	const beforeByPath = new Map<string, FileSnapshot>();
    26	const touchedPaths = new Set<string>();
    27	let activeAnswerStart: number | null = null;
    28	
    29	function hexToRgb(hex: string): [number, number, number] {
    30		const h = hex.replace("#", "");
    31		return [
    32			parseInt(h.slice(0, 2), 16),
    33			parseInt(h.slice(2, 4), 16),
    34			parseInt(h.slice(4, 6), 16),
    35		];
    36	}
    37	
    38	function colorHex(hex: string, text: string): string {
    39		const [r, g, b] = hexToRgb(hex);
    40		return `\x1b[38;2;${r};${g};${b}m${text}\x1b[0m`;
    41	}
    42	
    43	function formatElapsed(ms: number): string {
    44		const totalSeconds = Math.max(0, Math.floor(ms / 1000));
    45		const hours = Math.floor(totalSeconds / 3600);
    46		const minutes = Math.floor((totalSeconds % 3600) / 60);
    47		const seconds = totalSeconds % 60;
    48	
    49		if (hours > 0) return `${hours}h${minutes.toString().padStart(2, "0")}m`;
    50		if (minutes > 0) return `${minutes}m${seconds.toString().padStart(2, "0")}s`;
    51		return `${seconds}s`;
    52	}
    53	
    54	function readSnapshot(path: string): FileSnapshot {
    55		try {
    56			if (!existsSync(path)) return { kind: "text", content: null };
    57			const stat = statSync(path);
    58			if (!stat.isFile()) return { kind: "skipped", reason: "not a file" };
    59			if (stat.size > MAX_TEXT_BYTES) return { kind: "skipped", reason: "large file" };
    60			return { kind: "text", content: readFileSync(path, "utf8") };
    61		} catch (error) {
    62			return { kind: "skipped", reason: error instanceof Error ? error.message : String(error) };
    63		}
    64	}
    65	
    66	function splitLines(content: string): string[] {
    67		if (content.length === 0) return [];
    68		const lines = content.split("\n");
    69		if (lines[lines.length - 1] === "") lines.pop();
    70		return lines;
    71	}
    72	
    73	function shortestInsertDeleteScriptLength(beforeLines: string[], afterLines: string[]): number {
    74		let beforeStart = 0;
    75		let afterStart = 0;
    76		let beforeEnd = beforeLines.length;
    77		let afterEnd = afterLines.length;
    78	
    79		while (beforeStart < beforeEnd && afterStart < afterEnd && beforeLines[beforeStart] === afterLines[afterStart]) {
    80			beforeStart++;
    81			afterStart++;
    82		}
    83	
    84		while (
    85			beforeStart < beforeEnd &&
    86			afterStart < afterEnd &&
    87			beforeLines[beforeEnd - 1] === afterLines[afterEnd - 1]
    88		) {
    89			beforeEnd--;
    90			afterEnd--;
    91		}
    92	
    93		const oldLines = beforeLines.slice(beforeStart, beforeEnd);
    94		const newLines = afterLines.slice(afterStart, afterEnd);
    95		const oldCount = oldLines.length;
    96		const newCount = newLines.length;
    97	
    98		if (oldCount === 0) return newCount;
    99		if (newCount === 0) return oldCount;
   100	
   101		const max = oldCount + newCount;
   102		const offset = max + 1;
   103		const furthest = new Int32Array(max * 2 + 3);
   104		furthest.fill(-1);
   105		furthest[offset + 1] = 0;
   106	
   107		for (let distance = 0; distance <= max; distance++) {
   108			for (let diagonal = -distance; diagonal <= distance; diagonal += 2) {
   109				const index = offset + diagonal;
   110				const goDown = diagonal === -distance || (diagonal !== distance && furthest[index - 1] < furthest[index + 1]);
   111				let x = goDown ? furthest[index + 1] : furthest[index - 1] + 1;
   112				let y = x - diagonal;
   113	
   114				while (x < oldCount && y < newCount && oldLines[x] === newLines[y]) {
   115					x++;
   116					y++;
   117				}
   118	
   119				furthest[index] = x;
   120				if (x >= oldCount && y >= newCount) return distance;
   121			}
   122		}
   123	
   124		return max;
   125	}
   126	
   127	function diffLineStats(before: string | null, after: string | null): { added: number; removed: number } {
   128		if (before === after) return { added: 0, removed: 0 };
   129	
   130		const beforeLines = splitLines(before ?? "");
   131		const afterLines = splitLines(after ?? "");
   132		const distance = shortestInsertDeleteScriptLength(beforeLines, afterLines);
   133	
   134		return {
   135			added: Math.max(0, Math.round((distance - beforeLines.length + afterLines.length) / 2)),
   136			removed: Math.max(0, Math.round((distance + beforeLines.length - afterLines.length) / 2)),
   137		};
   138	}
   139	
   140	function toolPath(input: unknown): string | null {
   141		if (!input || typeof input !== "object") return null;
   142		const value = (input as { path?: unknown; file_path?: unknown }).path ??
   143			(input as { path?: unknown; file_path?: unknown }).file_path;
   144		return typeof value === "string" && value.length > 0 ? value : null;
   145	}
   146	
   147	function absoluteToolPath(ctx: ExtensionContext, input: unknown): string | null {
   148		const path = toolPath(input);
   149		return path === null ? null : resolve(ctx.cwd, path);
   150	}
   151	
   152	function displayPath(path: string, _cwd: string): string {
   153		return basename(path) || path;
   154	}
   155	
   156	function pathParts(path: string, cwd: string): string[] {
   157		const rel = relative(cwd, path);
   158		const displayPath = rel && !rel.startsWith("..") && !isAbsolute(rel) ? rel : path;
   159		return displayPath.split(/[\\/]+/).filter(Boolean);
   160	}
   161	
   162	function disambiguateDuplicateNames(rows: FileStats[], cwd: string) {
   163		const byName = new Map<string, FileStats[]>();
   164		for (const row of rows) {
   165			const group = byName.get(row.name) ?? [];
   166			group.push(row);
   167			byName.set(row.name, group);
   168		}
   169	
   170		for (const group of byName.values()) {
   171			if (group.length <= 1) continue;
   172	
   173			const partsByPath = new Map(group.map((row) => [row.path, pathParts(row.path, cwd)]));
   174			const maxDepth = Math.max(...Array.from(partsByPath.values(), (parts) => parts.length));
   175	
   176			for (let depth = 2; depth <= maxDepth; depth++) {
   177				const names = group.map((row) => (partsByPath.get(row.path) ?? [row.name]).slice(-depth).join("/"));
   178				if (new Set(names).size !== group.length) continue;
   179	
   180				for (let i = 0; i < group.length; i++) group[i].name = names[i];
   181				break;
   182			}
   183		}
   184	}
   185	
   186	function rememberBefore(path: string) {
   187		if (!beforeByPath.has(path)) beforeByPath.set(path, readSnapshot(path));
   188	}
   189	
   190	function clearSummary(ctx: ExtensionContext) {
   191		ctx.ui.setWidget(WIDGET_KEY, undefined);
   192	}
   193	
   194	function collectFileStats(ctx: ExtensionContext): FileStats[] {
   195		const rows: FileStats[] = [];
   196	
   197		for (const path of touchedPaths) {
   198			const before = beforeByPath.get(path);
   199			const after = readSnapshot(path);
   200			if (!before || before.kind !== "text" || after.kind !== "text") continue;
   201	
   202			const { added, removed } = diffLineStats(before.content, after.content);
   203			if (added === 0 && removed === 0) continue;
   204	
   205			const status = before.content === null ? "added" : after.content === null ? "deleted" : "modified";
   206			rows.push({ path, name: displayPath(path, ctx.cwd), status, added, removed });
   207		}
   208	
   209		disambiguateDuplicateNames(rows, ctx.cwd);
   210	
   211		const statusOrder = { modified: 0, added: 1, deleted: 2 } as const;
   212		rows.sort((a, b) => statusOrder[a.status] - statusOrder[b.status] || a.name.localeCompare(b.name));
   213		return rows;
   214	}
   215	
   216	function renderSummary(ctx: ExtensionContext, elapsedMs: number): string[] {
   217		const rows = collectFileStats(ctx);
   218		const elapsed = colorHex(CATPPUCCIN_MACCHIATO_PINK, formatElapsed(elapsedMs));
   219	
   220		if (rows.length === 0) return [elapsed];
   221	
   222		const totalAdded = rows.reduce((sum, row) => sum + row.added, 0);
   223		const totalRemoved = rows.reduce((sum, row) => sum + row.removed, 0);
   224		const firstLine = [
   225			elapsed,
   226			ctx.ui.theme.fg("dim", `${rows.length} ${rows.length === 1 ? "file" : "files"}`),
   227			ctx.ui.theme.fg("success", `+${totalAdded}`),
   228			ctx.ui.theme.fg("error", `-${totalRemoved}`),
   229		].join(" ");
   230	
   231		const detailLines = rows.slice(0, MAX_FILE_ROWS).map((row) => {
   232			const styledName = row.status === "added"
   233				? colorHex(CATPPUCCIN_MACCHIATO_GREEN, row.name)
   234				: row.status === "deleted"
   235					? colorHex(CATPPUCCIN_MACCHIATO_RED, row.name)
   236					: colorHex(CATPPUCCIN_MACCHIATO_BLUE, row.name);
   237	
   238			if (row.status === "added") return `${styledName} ${ctx.ui.theme.fg("success", `+${row.added}`)}`;
   239			if (row.status === "deleted") return `${styledName} ${ctx.ui.theme.fg("error", `-${row.removed}`)}`;
   240			return `${styledName} ${ctx.ui.theme.fg("success", `+${row.added}`)} ${ctx.ui.theme.fg("error", `-${row.removed}`)}`;
   241		});
   242	
   243		if (rows.length > MAX_FILE_ROWS) {
   244			detailLines.push(ctx.ui.theme.fg("dim", `… ${rows.length - MAX_FILE_ROWS} more`));
   245		}
   246	
   247		return [firstLine, ...detailLines];
   248	}
   249	
   250	export default function (pi: ExtensionAPI) {
   251		pi.on("session_start", async (_event, ctx) => {
   252			clearSummary(ctx);
   253		});
   254	
   255		pi.on("agent_start", async (_event, ctx) => {
   256			activeAnswerStart = Date.now();
   257			beforeByPath.clear();
   258			touchedPaths.clear();
   259			clearSummary(ctx);
   260		});
   261	
   262		pi.on("tool_call", async (event, ctx) => {
   263			if (event.toolName !== "edit" && event.toolName !== "write") return;
   264			const path = absoluteToolPath(ctx, event.input);
   265			if (path !== null) rememberBefore(path);
   266		});
   267	
   268		pi.on("tool_result", async (event, ctx) => {
   269			if (event.isError) return;
   270			if (event.toolName !== "edit" && event.toolName !== "write") return;
   271	
   272			const path = absoluteToolPath(ctx, event.input);
   273			if (path === null) return;
   274	
   275			rememberBefore(path);
   276			touchedPaths.add(path);
   277		});
   278	
   279		pi.on("agent_end", async (_event, ctx) => {
   280			const elapsedMs = activeAnswerStart === null ? 0 : Date.now() - activeAnswerStart;
   281			activeAnswerStart = null;
   282			ctx.ui.setWidget(WIDGET_KEY, renderSummary(ctx, elapsedMs), { placement: "aboveEditor" });
   283		});
   284	
   285		pi.on("session_shutdown", async (_event, ctx) => {
   286			activeAnswerStart = null;
   287			beforeByPath.clear();
   288			touchedPaths.clear();
   289			clearSummary(ctx);
   290		});
   291	}
