   797	import { isToolCallEventType } from "@earendil-works/pi-coding-agent";
   798	import type { MyToolInput } from "my-extension";
   799	
   800	pi.on("tool_call", (event) => {
   801	  if (isToolCallEventType<"my_tool", MyToolInput>("my_tool", event)) {
   802	    event.input.action;  // typed
   803	  }
   804	});
   805	```
