  const d = shortestInsertDeleteScriptLength(a,b);
  const ms = Number(process.hrtime.bigint()-start)/1e6;
  console.log(`worst-case ${n}+${n} lines: distance=${d}, elapsed=${ms.toFixed(1)}ms`);
